UPDATE NMCP_MCASH_CAN_TRG
SET RVISN_DTTM = SYSDATE
    ,RVISN_ID = 'BATCH'
    ,PROC_YN = #{procYn}
    ,PROC_DTTM = SYSDATE

    ,RSLT_CD = #{rsltCd}


    ,RSLT_MSG = #{rsltMsg}


    ,MCASH_SEQ = #{mcashSeq}

WHERE CAN_TRG_SEQ = #{canTrgSeq}

UPDATE NMCP_MCASH_USER
SET RVISN_DTTM = SYSDATE
    ,RVISN_ID = 'BATCH'
    ,END_DTTM = TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
    ,STATUS = #{status}
    ,EVNT_TYPE = #{envtType}
    ,EVNT_TYPE_DTL = #{envtTypeDtl}
WHERE USERID = #{userid}
